import{c as a,Q as t,j as n,m as r}from"./chunks/framework.BXc4yaFE.js";const w=JSON.parse('{"title":"The Rundown AI — 2026-04-28","description":"","frontmatter":{"title":"The Rundown AI — 2026-04-28","date":"2026-04-28T00:00:00.000Z","source":"The Rundown AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-28-the-rundown-ai.md","filePath":"research/ai-news/2026-04/2026-04-28-the-rundown-ai.md","lastUpdated":1779898012000}'),o={name:"research/ai-news/2026-04/2026-04-28-the-rundown-ai.md"};function i(s,e,p,m,u,l){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="🗞️-the-rundown-ai-—-2026-04-28" tabindex="-1">🗞️ The Rundown AI — 2026-04-28 <a class="header-anchor" href="#🗞️-the-rundown-ai-—-2026-04-28" aria-label="Permalink to &quot;🗞️ The Rundown AI — 2026-04-28&quot;">​</a></h1><blockquote><p>每日 AI 產業動態，通俗易懂、密度高 來源：<a href="https://rss.beehiiv.com/feeds/2R3C6Bt5wj.xml" target="_blank" rel="noreferrer">The Rundown AI</a></p></blockquote><hr><h2 id="openai-and-microsoft-s-new-open-relationship" tabindex="-1"><a href="https://www.therundown.ai/p/openai-and-microsoft-new-open-relationship" target="_blank" rel="noreferrer">OpenAI and Microsoft&#39;s new open relationship</a> <a class="header-anchor" href="#openai-and-microsoft-s-new-open-relationship" aria-label="Permalink to &quot;[OpenAI and Microsoft&#39;s new open relationship](https://www.therundown.ai/p/openai-and-microsoft-new-open-relationship)&quot;">​</a></h2><p><em>🗞️ The Rundown AI | 2026-04-28</em></p><p><a href="./">Read Online</a> | <a href="https://www.therundown.ai/subscribe?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Sign Up</a> | <a href="https://therundownai.typeform.com/to/kraZ1TSO?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Advertise</a></p><p>[](<a href="https://you.com/resources/how-we-evaluate-ai-search?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/how-we-evaluate-ai-search?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_428&amp;utm_content=rundown_primary_428)</p><p>Good morning, AI enthusiasts. The Microsoft-OpenAI relationship is no longer an exclusive marriage… But it’s also not exactly a breakup either.</p><p>The new deal terms allow OpenAI to date around in the cloud (hello, Amazon), while Microsoft keeps the awkward-but-lucrative role of ex with benefits: less control, but still very much getting paid.</p><p>P.S. — We’re hiring for five new roles at The Rundown to continue scaling our mission to help 1B+ people turn AI into a superpower. Check out the available roles <a href="https://jobs.therundown.ai/jobs?q=the+rundown&amp;category=&amp;location=&amp;location_id=&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">here</a> and earn a $2,000 referral bonus if you help us hire someone full-time.</p><p>In today’s AI rundown:</p><p>OpenAI rewrites Microsoft deal, removes AGI clause</p><p>Beijing blocks Meta&#39;s $2B Manus deal</p><p>Set up AI teammates with ChatGPT Workspace Agents</p><p>AlphaGo creator’s new $1.1B &#39;superlearner&#39; lab</p><p>4 new AI tools, community workflows, and more</p><p>LATEST DEVELOPMENTS</p><p>OPENAI &amp; MICROSOFT</p><p>📜 <a href="https://openai.com/index/next-phase-of-microsoft-partnership/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">OpenAI rewrites Microsoft deal, removes AGI clause</a></p><p>Image source: Images 2.0 / The Rundown</p><p>The Rundown: OpenAI and Microsoft <a href="https://openai.com/index/next-phase-of-microsoft-partnership/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">reworked</a> their partnership terms, ending Microsoft&#39;s exclusivity over OAI’s IP, killing the AGI clause, and freeing OpenAI to ship products on any cloud while Microsoft keeps a revenue share through 2030.</p><p>The details:</p><p>OAI can now utilize rival clouds like <a href="https://x.com/ajassy/status/2048806022253609115?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Amazon Bedrock</a>, with Microsoft still remaining a main cloud partner with Azure-first launch access through 2032.</p><p>The agreement settles Microsoft&#39;s reported <a href="https://www.rundown.ai/articles/google-bets-on-vibe-design-with-stitch?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">lawsuit threat</a> over the $50B Amazon-OpenAI deal that gave AWS exclusive rights to OAI&#39;s Frontier platform.</p><p>Amazon CEO Andy Jassy called the announcement “very interesting”, coming after OpenAI CRO Denise Dresser’s <a href="https://www.rundown.ai/articles/what-happens-when-ai-runs-a-retail-store?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">memo</a> talking up its Bedrock platform.</p><p>Microsoft will stop paying revenue share to OAI, with both companies&#39; obligations now running on calendar dates instead of an AGI announcement.</p><p>Why it matters: It’s no secret that this relationship has gone sour, and these changes remove the exclusivity that Dresser said “limited” OpenAI’s ability to meet enterprises where they were. The AI giant now gets to date around in the cloud, while Microsoft locks in a six-year revenue stream without an ambiguous AGI clause hanging over it.</p><p>TOGETHER WITH YOU.COM</p><p>📈 [Do you know how to evaluate your web search APIs?](<a href="https://you.com/resources/how-we-evaluate-ai-search?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/how-we-evaluate-ai-search?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_428&amp;utm_content=rundown_primary_428)</p><p>[](<a href="https://you.com/resources/how-we-evaluate-ai-search?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/how-we-evaluate-ai-search?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_428&amp;utm_content=rundown_primary_428)</p><p>The Rundown: Teams often pick a web search provider by running a few test queries and hoping for the best—a recipe for hallucinations and unpredictable failures. This technical guide from [You.com](<a href="https://you.com/resources/how-we-evaluate-ai-search?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/how-we-evaluate-ai-search?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_428&amp;utm_content=rundown_primary_428) gives you access to an exact framework to evaluate web search APIs.</p><p>What you’ll get:</p><p>A four-phase framework for evaluating AI search</p><p>How to build a golden set of queries that predicts real-world performance</p><p>Metrics and code for measuring accuracy</p><p>Go from “looks good” to proven quality. [Learn how to run an eval](<a href="https://you.com/resources/how-we-evaluate-ai-search?utm_campaign=28104480-The" target="_blank" rel="noreferrer">https://you.com/resources/how-we-evaluate-ai-search?utm_campaign=28104480-The</a> Rundown Q4&amp;utm_source=external-newsletter&amp;utm_medium=email&amp;utm_term=rundown_primary_428&amp;utm_content=rundown_primary_428).</p><p>META &amp; MANUS</p><p>🚫 <a href="https://www.cnbc.com/2026/04/27/meta-manus-china-blocks-acquisition-ai-startup.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Beijing blocks Meta&#39;s $2B Manus deal</a></p><p>Image source: Images 2.0 / The Rundown</p><p>The Rundown: China <a href="https://www.cnbc.com/2026/04/27/meta-manus-china-blocks-acquisition-ai-startup.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">vetoed</a> Meta&#39;s $2B Manus acquisition and told the companies to withdraw the AI startup deal, turning a Singapore-based company with Chinese roots into a warning shot for founders trying to move talent and tech outside Beijing&#39;s reach.</p><p>The details:</p><p>Meta announced the $2B deal in December, with Chinese officials opening a January probe into export-control and foreign-investment rules.</p><p>China&#39;s National Development and Reform Commission said it would bar foreign investment in Manus, directing Meta and the startup to undo the deal.</p><p>Meta said the two teams were already &quot;deeply integrated&quot; at its Singapore office, and Manus&#39;s site already read &quot;now part of Meta.&quot;</p><p>The order lands weeks before Trump&#39;s planned May meeting with Xi in Beijing, with Manus executives reportedly barred from leaving China during the probe.</p><p>Why it matters: Beijing just made AI talent a national security asset, applying to startups the same type of export-control logic the U.S. uses on chips. With the two already intertwined and Meta saying “the transaction complied fully with applicable law”, it’s unclear how an unwind will even work — or if the tech giant will comply.</p><p>AI TRAINING</p><p>🤖 <a href="https://app.therundown.ai/guides/set-up-useful-ai-teammates-with-new-chatgpt-workspace-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Set up AI teammates with ChatGPT Workspace Agents</a></p><p><a href="https://app.therundown.ai/guides/set-up-useful-ai-teammates-with-new-chatgpt-workspace-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer"></a></p><p>The Rundown: In this guide, you will learn how to set up AI teammates that are actually useful using ChatGPT’s new Workspace Agents tool (currently in research preview for Business, Enterprise, Edu, and Teachers plans).</p><p>Step-by-step:</p><p>Go to <a href="https://chatgpt.com/agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">chatgpt.com/agents</a>, click Create agent, and pick a tool, database, or process for this agent to “own”.</p><p>Prompt: “Create an agent that manages [lead pipeline, Google Docs folder, Notion database, etc.]. It should do 3 main tasks that can run autonomously on schedules to save me time.”</p><p>Follow the setup prompts to add integrations and define what the agent should touch. Codex will look around your integrations to best set up the agent.</p><p>Return to the <a href="https://chatgpt.com/agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Agents page</a>, select your new agent, and try each of the main tasks. You can click the Schedule button to have the agent run every day.</p><p>Pro tip: If you don’t have a ChatGPT business plan, don’t worry. You can still use this prompt + approach in other tools to create helpful agents.</p><p>PRESENTED BY HEAR.COM</p><p>👂 <a href="https://www.hear.com/d/best_hearing_aids_dis08/?act=ACT0000098496ACT&amp;utm_source=rundownai&amp;utm_medium=direct-buy&amp;utm_campaign=us_en_al_hea_directbuy_rundownai_hea-lightbulb-double_acq_all_sec_042026_ACT0000098496ACT" target="_blank" rel="noreferrer">The AI in your ear you haven&#39;t heard of</a></p><p><a href="https://www.hear.com/d/best_hearing_aids_dis08/?act=ACT0000098496ACT&amp;utm_source=rundownai&amp;utm_medium=direct-buy&amp;utm_campaign=us_en_al_hea_directbuy_rundownai_hea-lightbulb-double_acq_all_sec_042026_ACT0000098496ACT" target="_blank" rel="noreferrer"></a></p><p>The Rundown: Horizon IX by <a href="https://www.hear.com/d/best_hearing_aids_dis08/?act=ACT0000098496ACT&amp;utm_source=rundownai&amp;utm_medium=direct-buy&amp;utm_campaign=us_en_al_hea_directbuy_rundownai_hea-lightbulb-double_acq_all_sec_042026_ACT0000098496ACT" target="_blank" rel="noreferrer">hear.com</a> uses MultiBeam AI to identify individual speakers and shift microphone focus in real time — automatically adapting to any environment without a single manual adjustment.</p><p>With Horizon IX, you&#39;ll:</p><p>Hear what 10,000 scans per second actually sounds like</p><p>Track individual speakers as conversations shift — zero manual tuning</p><p>Adapt instantly across any environment, from a packed conference room to a busy street</p><p>This is what it sounds like when the hardware finally catches up in AI. <a href="https://www.hear.com/d/best_hearing_aids_dis08/?act=ACT0000098496ACT&amp;utm_source=rundownai&amp;utm_medium=direct-buy&amp;utm_campaign=us_en_al_hea_directbuy_rundownai_hea-lightbulb-double_acq_all_sec_042026_ACT0000098496ACT" target="_blank" rel="noreferrer">Put Horizon IX to the test</a>.</p><p>INEFFABLE INTELLIGENCE</p><p>🧠 <a href="https://ineffable.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">AlphaGo creator’s new $1.1B &#39;superlearner&#39; lab</a></p><p>Image source: Ineffable Intelligence</p><p>The Rundown: Ex-DeepMind researcher David Silver <a href="https://ineffable.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">launched</a> Ineffable Intelligence, a London lab that raised $1.1B at a $5.1B valuation to build an AI that learns from experience instead of training data, to “make first contact with superintelligence”.</p><p>The details:</p><p>Silver led DeepMind&#39;s reinforcement learning team for a decade, building acclaimed models <a href="https://deepmind.google/research/alphago/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">AlphaGo</a>, AlphaZero, AlphaStar, and AlphaProof.</p><p>Ineffable’s models skip pre-training and human data, letting agents learn from experience in simulations — creating what Silver calls a &quot;superlearner.&quot;</p><p>Silver <a href="https://www.wired.com/story/david-silver-ai-ineffable-intelligence-reinforcement-learning/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">framed</a> human data as &quot;a kind of fossil fuel&quot; and his approach as &quot;a renewable fuel, a model that can just learn and learn and learn forever.”</p><p>The $1.1B is Europe&#39;s largest seed ever, with Ineffable claiming success would “represent a scientific breakthrough of comparable magnitude to Darwin.&quot;</p><p>Why it matters: Yann Lecun’s theory that LLMs are a dead end has gotten some powerful companies, with AMI Labs, Recursive Superintelligence, and now Ineffable ($1.1B) all raising on variations of the view. Silver’s track record speaks for itself, and the more brilliant minds taking different paths towards AGI, the better.</p><p>QUICK HITS</p><p>🛠️ <a href="https://www.rundown.ai/tools?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Trending AI Tools</a></p><p>🎨 <a href="https://www.rundown.ai/tools/firefly-ai-assistant?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Firefly AI Assistant</a> - Adobe&#39;s AI agent for multi-app Creative Cloud work</p><p>🎥 <a href="https://www.rundown.ai/tools/kling-3-0?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Kling 3.0</a> - New 4K mode for generating AI videos with cinematic quality</p><p>📽️ <a href="https://www.rundown.ai/tools/happy-horse?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">HappyHorse</a> - Alibaba’s new SOTA video generation model</p><p>❤️ <a href="https://www.rundown.ai/tools/lovable?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Lovable</a> - AI app building platform, now available via mobile app</p><p>📰 <a href="https://www.rundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Everything else in AI today</a></p><p>Uncharted: The AI safety &amp; security summit, May 5 – learn how to operationalize AI safety and close the AI security gap with proven enterprise strategies. <a href="https://experience.telusdigital.com/uncharted-ai-safety-security-summit-2026?utm_campaign=2026-Q2_fuelix_cross_us_pros_en&amp;utm_medium=third_mofu_mql_&amp;utm_source=rndwnai&amp;utm_content=uncharted-summit-may-2026_reg_txt-spot" target="_blank" rel="noreferrer">Register for free</a>.*</p><p>The trial between Elon Musk and OpenAI <a href="https://www.cnbc.com/2026/04/27/musk-altman-trial-openai-jury-selection.html?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">kicked off</a> on Monday with the start of jury selection, with the two sides <a href="https://x.com/elonmusk/status/2048801964457140540?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">trading</a> barbs <a href="https://x.com/OpenAINewsroom/status/2048776645142872368?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">on X</a> ahead of opening statements.</p><p>Tech analyst Ming-Chi Kuo <a href="https://x.com/mingchikuo/status/2048587389791269182?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">said</a> OpenAI is working on its own smartphone alongside MediaTek and Qualcomm, with native AI agents and production likely in 2028.</p><p>Adobe <a href="https://blog.adobe.com/en/publish/2026/04/15/introducing-firefly-ai-assistant-new-way-create-with-our-creative-agent?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">opened</a> access to its new Firefly AI Assistant in public beta, letting creators prompt multi-app Creative Cloud workflows while keeping outputs editable.</p><p>Alibaba’s new Happy Horse video model <a href="https://x.com/HappyHorseATH/status/2048709544566718908?s=20&amp;utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">rolled out</a> across video platforms, with the release taking the <a href="https://artificialanalysis.ai/video/models?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">top spot</a> on Artificial Analysis’s video leaderboard.</p><p>Taylor Swift <a href="https://variety.com/2026/music/news/taylor-swift-trademark-voice-likeness-ai-misuse-1236731401/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">filed</a> three federal trademarks for her likeness and voice, joining actor Matthew McConaughey in taking legal action to fight and prevent AI deepfakes.</p><p>*Sponsored Listing</p><p>COMMUNITY</p><p>🤝 <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Community AI workflows</a></p><p>Every newsletter, we showcase how a reader is using AI to work smarter, save time, or make life easier.</p><p>Today’s workflow comes from reader Lydia F. in North Liberty, Iowa:</p><p>&quot;I used Codex to build a web-based application to help my teenage daughter study for the Iowa Driver&#39;s Permit knowledge test. I uploaded the full test study manual from the Department of Transportation and a couple of practice tests, then built a bank of 200 flashcards and a quiz feature that pulls 25 questions from a bank of 200 multiple-choice and True/False questions (with the most common topics weighted to appear more frequently).</p><p>I shared the URL with other moms of teens in my town. Now that studying for the driver&#39;s test is so easy, our teens have no excuse!&quot;</p><p>How do you use AI? Tell us <a href="https://www.videoask.com/ffohxg3vc?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">here</a>.</p><p>🎓 <a href="https://app.therundown.ai/?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Highlights: News, Guides &amp; Events</a></p><p>Read our last AI newsletter: <a href="https://www.rundown.ai/articles/deepseek-resurfaces-with-cheap-capable-v4?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">DeepSeek resurfaces with cheap, capable V4</a></p><p>Read our last Tech newsletter: <a href="https://www.rundown.ai/articles/big-tech-20m-lobbying-blitz?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Big Tech’s $20B lobbying blitz</a></p><p>Read our last Robotics newsletter: <a href="https://www.rundown.ai/articles/the-chinese-robot-ban-is-coming?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">The Chinese robot ban is coming</a></p><p>Today’s AI tool guide: <a href="https://app.therundown.ai/guides/set-up-useful-ai-teammates-with-new-chatgpt-workspace-agents?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Set up AI teammates with Workspace Agents</a></p><p>RSVP to workshop Thursday @ 2PM EST: <a href="https://app.therundown.ai/calendar-events/69e77469e7e908f6d4ebdf72?utm_source=www.therundown.ai&amp;utm_medium=newsletter&amp;utm_campaign=openai-and-microsoft-s-new-open-relationship" target="_blank" rel="noreferrer">Codex for non-technical operators</a></p><p>See you soon,</p><p>Rowan, Joey, Zach, Shubham, and Jennifer — the humans behind The Rundown</p><hr>',105)])])}const c=a(o,[["render",i]]);export{w as __pageData,c as default};
